/* content-box (default) */
.element {
  width: 200px;
  padding: 20px;
  border: 5px solid black;
  /* Actual rendered width: 200 + 40 + 10 = 250px */
}

/* border-box (recommended) */
.element {
  box-sizing: border-box;
  width: 200px;
  padding: 20px;
  border: 5px solid black;
  /* Actual rendered width: 200px */
  /* Content area: 200 - 40 - 10 = 150px */
}

/* Global reset (best practice) */
*, *::before, *::after {
  box-sizing: border-box;
}

/* Vertical margins collapse */
.box-a { margin-bottom: 20px; }
.box-b { margin-top: 30px; }
/* Gap between A and B = 30px (not 50px) */

/* Margins do NOT collapse when: */
/* 1. Horizontal margins */
.inline { margin-left: 10px; margin-right: 10px; }

/* 2. Parent has padding or border */
.parent {
  padding: 1px; /* prevents child margin from collapsing */
}

/* 3. Flex/Grid containers */
.flex-parent {
  display: flex;
  flex-direction: column;
  /* Child margins do NOT collapse here */
}

/* Base: mobile styles */
.container {
  padding: 1rem;
}
.grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

/* Tablet: 768px+ */
@media (min-width: 768px) {
  .container { padding: 2rem; }
  .grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

/* Desktop: 1024px+ */
@media (min-width: 1024px) {
  .container {
    max-width: 1200px;
    margin: 0 auto;
  }
  .grid {
    grid-template-columns: repeat(3, 1fr);
  }
}

/* Fluid typography */
h1 {
  font-size: clamp(1.5rem, 4vw, 3rem);
}

// localStorage: persists across sessions
localStorage.setItem('theme', 'dark');
localStorage.getItem('theme'); // 'dark'
localStorage.removeItem('theme');
localStorage.clear(); // remove all

// Store objects (must serialize)
const user = { name: 'John', age: 25 };
localStorage.setItem('user', JSON.stringify(user));
const stored = JSON.parse(
  localStorage.getItem('user')
);

// sessionStorage: same API, per-tab lifetime
sessionStorage.setItem('formDraft', '{...}');
// Gone when tab closes

// Listen for storage changes (cross-tab)
window.addEventListener('storage', (e) => {
  console.log(e.key, e.oldValue, e.newValue);
  // Only fires in OTHER tabs
});

// Check support
if ('geolocation' in navigator) {
  // One-time position
  navigator.geolocation.getCurrentPosition(
    (position) => {
      const { latitude, longitude } = position.coords;
      console.log(`Lat: ${latitude}, Lng: ${longitude}`);
      console.log(`Accuracy: ${position.coords.accuracy}m`);
    },
    (error) => {
      switch (error.code) {
        case error.PERMISSION_DENIED:
          console.log('User denied geolocation');
          break;
        case error.POSITION_UNAVAILABLE:
          console.log('Location unavailable');
          break;
        case error.TIMEOUT:
          console.log('Request timed out');
          break;
      }
    },
    { enableHighAccuracy: true, timeout: 10000 }
  );

  // Watch position (continuous)
  const watchId = navigator.geolocation.watchPosition(
    (pos) => console.log(pos.coords)
  );
  navigator.geolocation.clearWatch(watchId);
}

// Push new state (no page reload)
history.pushState(
  { page: 'about' },  // state object
  '',                  // title (ignored by most browsers)
  '/about'             // new URL
);

// Replace current state
history.replaceState(
  { page: 'home' }, '', '/'
);

// Listen for back/forward navigation
window.addEventListener('popstate', (e) => {
  console.log('Navigation:', e.state);
  // Render the appropriate page
  renderPage(e.state?.page || 'home');
});

// Go back/forward programmatically
history.back();
history.forward();
history.go(-2); // go back 2 pages

/* Element selector */
p { color: #333; }

/* Class selector */
.highlight { background: yellow; }

/* ID selector */
#hero { height: 100vh; }

/* Universal selector */
* { margin: 0; padding: 0; }

/* Attribute selectors */
[type="email"] { border-color: blue; }
[href^="https"] { color: green; }  /* starts with */
[href$=".pdf"] { color: red; }     /* ends with */
[class*="btn"] { cursor: pointer; } /* contains */

/* Grouping */
h1, h2, h3 { font-family: serif; }

/* Chaining (must match all) */
input.large[required] {
  border: 2px solid red;
}

/* Descendant: any level deep */
.card p { margin-bottom: 0.5rem; }
/* Matches <div class='card'><div><p>this</p></div></div> */

/* Child: direct children only */
.card > p { font-weight: bold; }
/* Only matches <div class='card'><p>this</p></div> */

/* Adjacent sibling: immediately after */
h2 + p { font-size: 1.2rem; }
/* Only the first <p> right after <h2> */

/* General sibling: all after */
h2 ~ p { color: #666; }
/* All <p> elements after <h2> at same level */

/* Combining combinators */
.sidebar > ul > li > a:hover {
  color: blue;
}

/* Style links by type */
a[href^="http"]:not([href*="mysite.com"]) {
