.wide { grid-column: span 2; }
.tall { grid-row: span 2; }

/* Alignment in grid */
.grid {
  /* Align all items */
  justify-items: center; /* horizontal */
  align-items: center;   /* vertical */

  /* Align the grid itself */
  justify-content: center;
