}

/* Transition on base state */
.button {
  background: #3b82f6;
  color: white;
  padding: 0.75rem 1.5rem;
  border-radius: 0.375rem;
  transition: background 0.2s ease,
             transform 0.2s ease;
}
.button:hover {
  background: #2563eb;
  transform: translateY(-2px);
}
.button:active {
  transform: translateY(0);
}

/* Transition all (use sparingly) */
.card {
  transition: all 0.3s ease;
  /* Transitions ANY property that changes */
  /* Can cause unexpected animations */
}

/* Different timing per property */
.element {
  transition:
    opacity 0.3s ease,
    transform 0.5s cubic-bezier(0.4, 0, 0.2, 1);
}

/* Built-in timing functions */
.ease     { transition: transform 0.3s ease; }
.linear   { transition: transform 0.3s linear; }
.ease-in  { transition: transform 0.3s ease-in; }
.ease-out { transition: transform 0.3s ease-out; }

/* Custom cubic-bezier */
.bouncy {
  transition: transform 0.5s
    cubic-bezier(0.68, -0.55, 0.265, 1.55);
  /* Overshoots then settles */
}

/* Common custom curves */
.smooth-out {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  /* Material Design standard easing */
}

/* Delay */
.delayed {
  transition: opacity 0.3s ease 0.1s;
  /* 0.1s delay before animation starts */
}

/* Staggered children (with delay) */
.list-item:nth-child(1) { transition-delay: 0.0s; }
.list-item:nth-child(2) { transition-delay: 0.1s; }
.list-item:nth-child(3) { transition-delay: 0.2s; }

/* Fade in/out with visibility */
.tooltip {
  opacity: 0;
  visibility: hidden;
  transition: opacity 0.2s ease,
             visibility 0.2s ease;
}
.trigger:hover .tooltip {
  opacity: 1;
  visibility: visible;
}

/* Slide down menu */
.menu {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.3s ease-out;
}
.menu.open {
  max-height: 500px;
  /* Generous max-height, transition handles it */
}

/* Color theme transition */
:root {
  --bg: #fff;
  --text: #111;
}
.dark {
  --bg: #111;
  --text: #fff;
}
body {
  background: var(--bg);
  color: var(--text);
  transition: background 0.3s ease, color 0.3s ease;
}

/* Define keyframes */
@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(20px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Apply animation */
.card {
  animation: fadeInUp 0.5s ease-out forwards;
  /* forwards: keeps the final state */
}

/* Multi-step animation */
@keyframes pulse {
  0%   { transform: scale(1); }
  50%  { transform: scale(1.05); }
  100% { transform: scale(1); }
}
.badge {
  animation: pulse 2s ease-in-out infinite;
}

/* Shorthand */
.element {
  animation: name 1s ease 0.5s 3 alternate forwards;
  /* name duration timing delay count direction fill */
}

/* Loading spinner */
@keyframes spin {
  to { transform: rotate(360deg); }
}
.spinner {
  width: 2rem;
  height: 2rem;
  border: 3px solid #e5e7eb;
  border-top-color: #3b82f6;
  border-radius: 50%;
  animation: spin 0.8s linear infinite;
}

/* Skeleton loading shimmer */
@keyframes shimmer {
  0%   { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}
.skeleton {
  background: linear-gradient(
    90deg, #f0f0f0 25%, #e0e0e0 50%, #f0f0f0 75%
  );
  background-size: 200% 100%;
  animation: shimmer 1.5s infinite;
}

/* Staggered entrance */
.list-item {
  animation: fadeInUp 0.4s ease-out forwards;
  opacity: 0;
}
.list-item:nth-child(1) { animation-delay: 0.0s; }
.list-item:nth-child(2) { animation-delay: 0.1s; }
.list-item:nth-child(3) { animation-delay: 0.2s; }

/* GOOD: animate only transform and opacity */
@keyframes slideIn {
  from {
    transform: translateX(-100%);
    opacity: 0;
  }
  to {
    transform: translateX(0);
    opacity: 1;
  }
}

/* BAD: animating layout properties */
@keyframes badSlide {
  from { margin-left: -100%; } /* triggers layout */
  to { margin-left: 0; }
}

/* Respect user preferences */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

/* Pause on hover (for autoplaying animations) */
.carousel {
  animation: scroll 10s linear infinite;
}
.carousel:hover {
  animation-play-state: paused;
}

/* Translate: move element */
.move {
  transform: translateX(50px);
  transform: translateY(-20px);
  transform: translate(50px, -20px);
}

/* Rotate: spin element */
.rotate {
  transform: rotate(45deg);
  transform-origin: top left; /* pivot point */
}

/* Scale: resize element */
.grow {
  transform: scale(1.5);      /* 150% */
  transform: scaleX(2);       /* stretch horizontal */
}

/* Skew: slant element */
.skew {
  transform: skew(10deg, 5deg);
}

/* Combining transforms (order matters!) */
.combined {
  transform: translate(100px, 0) rotate(45deg) scale(0.8);
  /* Applied right-to-left:
     1. scale, 2. rotate, 3. translate */
}

/* Center with transform */
.center-absolute {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

/* Perspective on parent creates depth */
.scene {
  perspective: 1000px;
  /* Lower value = more dramatic 3D effect */
}

/* 3D card flip */
.card-container {
  perspective: 800px;
  width: 300px;
  height: 200px;
}
.card {
  width: 100%;
  height: 100%;
  position: relative;
  transform-style: preserve-3d;
  transition: transform 0.6s ease;
}
.card-container:hover .card {
  transform: rotateY(180deg);
}
.card-front, .card-back {
  position: absolute;
  inset: 0;
  backface-visibility: hidden;
}
.card-back {
  transform: rotateY(180deg);
}

/* Hover lift effect */
.card {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}
.card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 24px rgb(0 0 0 / 0.15);
}

/* Image zoom on hover */
.image-container {
  overflow: hidden;
  border-radius: 0.5rem;
}
.image-container img {
  transition: transform 0.3s ease;
}
.image-container:hover img {
  transform: scale(1.1);
}

/* Tilt effect with perspective */
.tilt:hover {
  transform: perspective(500px)
    rotateX(5deg) rotateY(-5deg);
}

/* User action states */
.link:hover { color: blue; }
.link:active { color: red; }
.input:focus { border-color: blue; }
.input:focus-visible {
  outline: 2px solid blue;
  /* Only shows for keyboard focus, not mouse */
}

/* Structural */
li:first-child { font-weight: bold; }
li:last-child { border-bottom: none; }
li:nth-child(odd) { background: #f9f9f9; }
li:nth-child(3n) { color: red; } /* every 3rd */
li:nth-child(n+4) { opacity: 0.7; } /* 4th onwards */

/* Form states */
input:required { border-left: 3px solid red; }
input:valid { border-color: green; }
