/* Form validation styling */
.field:has(input:invalid) {
  border-color: red;
}
.field:has(input:valid) {
  border-color: green;
}
.form:has(input:invalid) .submit-btn {
  opacity: 0.5;
  pointer-events: none;
}

/* Conditional layouts */
.grid:has(> :nth-child(4)) {
  grid-template-columns: repeat(2, 1fr);
}
.grid:has(> :nth-child(7)) {
  grid-template-columns: repeat(3, 1fr);
}

/* Previous sibling selector (reverse + ) */
.item:has(+ .item:hover) {
  /* Style item BEFORE the hovered item */
  transform: scale(0.95);
}

/* Native CSS nesting (no Sass needed!) */
.card {
  background: white;
  border-radius: 0.5rem;

  /* Nested selector */
  & .title {
    font-size: 1.25rem;
    font-weight: 600;
  }

  /* & is optional for pseudo-classes */
  &:hover {
    box-shadow: 0 4px 12px rgb(0 0 0 / 0.1);
  }

  /* Nested media query */
  @media (min-width: 768px) {
    padding: 2rem;

    & .title {
      font-size: 1.5rem;
    }
  }

  /* BEM with nesting */
  &__body {
    padding: 1.5rem;
  }
  &--featured {
    border: 2px solid #3b82f6;
  }
}

/* Compiles mentally to:
   .card { }
   .card .title { }
   .card:hover { }
   .card__body { }
   .card--featured { } */

/* Define layer order (lowest to highest priority) */
@layer reset, base, components, utilities;

/* Reset layer (lowest priority) */
@layer reset {
  * { margin: 0; padding: 0; box-sizing: border-box; }
}

/* Base layer */
@layer base {
  body { font-family: system-ui; line-height: 1.6; }
  a { color: #3b82f6; }
}

/* Components layer */
@layer components {
  .btn {
    padding: 0.75rem 1.5rem;
    border-radius: 0.375rem;
  }
  .card {
    background: white;
    border-radius: 0.5rem;
  }
}

/* Utilities layer (highest priority) */
@layer utilities {
  .hidden { display: none !important; }
  .text-center { text-align: center; }
}

/* Utilities ALWAYS override components,
   regardless of specificity!
   .card has higher specificity than .hidden,
   but utilities layer wins */

/* Un-layered styles beat ALL layers */

@media print {
  /* Hide non-essential elements */
  nav, footer, .sidebar, .ads,
  .no-print, button {
    display: none !important;
  }

  /* Reset colors for print */
  body {
    color: black;
    background: white;
    font-size: 12pt;
    line-height: 1.5;
  }

  /* Show link URLs */
  a[href]::after {
    content: ' (' attr(href) ')';
    font-size: 0.8em;
    color: #666;
  }
  a[href^="#"]::after,
  a[href^="javascript:"]::after {
    content: ''; /* skip internal/JS links */
  }

  /* Page settings */
  @page {
    margin: 2cm;
    size: A4;
  }

  /* Avoid breaking inside elements */
  h2, h3, img, table {
    break-inside: avoid;
  }
  h2, h3 {
    break-after: avoid;
  }

  /* Force background printing */
  .badge {
    print-color-adjust: exact;
    -webkit-print-color-adjust: exact;
  }
}

/* Define theme tokens */
:root {
  color-scheme: light dark;
  /* Tells browser to style native controls */

  --bg: #ffffff;
  --bg-surface: #f9fafb;
  --text: #111827;
  --text-muted: #6b7280;
  --border: #e5e7eb;
  --shadow: 0 1px 3px rgb(0 0 0 / 0.1);
}

/* OS preference: auto dark mode */
@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f172a;
    --bg-surface: #1e293b;
    --text: #f1f5f9;
    --text-muted: #94a3b8;
    --border: #334155;
    --shadow: 0 1px 3px rgb(0 0 0 / 0.4);
  }
}

/* Manual toggle: class on html element */
html.dark {
  --bg: #0f172a;
  --bg-surface: #1e293b;
  --text: #f1f5f9;
  --text-muted: #94a3b8;
  --border: #334155;
  --shadow: 0 1px 3px rgb(0 0 0 / 0.4);
}

/* Apply tokens everywhere */
body {
  background: var(--bg);
  color: var(--text);
}
.card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
}
